   410|    default:
   411|      return {
   412|        taskId: task.id,
   413|        assignee: task.assignee,
   414|        platform: 'unknown',
   415|        success: false,
   416|        status: null,
   417|        response: null,
   418|        error: `Unknown platform for assignee "${task.assignee}". Cannot route.`,
   419|      };
