  return registry;
}

// ---------------------------------------------------------------------------
// Convenience: match a task to an agent
// ---------------------------------------------------------------------------

/**
 * High-level: given a task object, find the best agent from a registry.
 *
 * @param {Object} task - A task with at least { type, assignee? }
 * @param {AgentRegistry} registry
 * @returns {{agent: AgentCard|null, explicit: boolean}}
 *   - agent: best matching agent (or null)
 *   - explicit: true if task had an explicit assignee that was found
 */
export function matchAgent(task, registry) {
  // If task has an explicit assignee, look it up directly
  if (task.assignee) {
    const explicit = registry.get(task.assignee);
    if (explicit && explicit.available) {
      return { agent: explicit, explicit: true };
    }
  }

  // Otherwise, find best match by task type and capabilities
  const criteria = {
    taskType: task.type || 'code',
    requiredCapabilities: task.requiredCapabilities || [],
    preferredCapabilities: task.preferredCapabilities || [],
    preferredCostTier: task.preferredCostTier || undefined,
  };

  const best = registry.bestMatch(criteria);
  return { agent: best, explicit: false };
}
