assert(smartResult2.success, 'Capability dispatch succeeded');
assert(smartResult2.matchType === 'capability', 'Match type is capability');
assert(smartResult2.agentCard !== undefined, 'Has agent card annotation');

// Smart dispatch with custom registry
const customReg = new AgentRegistry();
customReg.register({
  id: 'special-agent',
  platform: 'hermes',
  taskTypes: ['special'],
  capabilities: ['magic'],
  costTier: 'low',
});

const smartResult3 = await smartDispatch(
  { id: 'T03', type: 'special' },
  { dryRun: true, registry: customReg }
);
assert(smartResult3.agentCard === 'special-agent', 'Custom registry used');

// Fallback to legacy when no match
const emptyReg = new AgentRegistry();
const smartResult4 = await smartDispatch(
  { id: 'T04', type: 'code', assignee: 'hermes-ceo' },
  { dryRun: true, registry: emptyReg }
);
assert(smartResult4.success, 'Legacy fallback works');
assert(smartResult4.platform === 'hermes', 'Legacy detected hermes');

// ===========================================================================
// Test 17: Cross-module integration
// ===========================================================================

console.log('\n=== Test 17: Cross-Module Integration ===');

// Create a slice, generate a contract, match agents, track costs
const testSlice = new Slice({
  id: 'S-INT',
  name: 'Integration Test Slice',
  phase: SLICE_PHASE.EXECUTE,
  tasks: [
    new Task({ id: 'INT-01', subject: 'Build API', assignee: 'hermes-ceo', type: 'code', wave: 1, verify: 'API responds' }),
    new Task({ id: 'INT-02', subject: 'Research case law', type: 'research', wave: 1, verify: 'Report generated' }),
  ],
});

// 1. Generate contract
const intContract = contractFromSlice(testSlice, { milestoneId: 'M001' });
intContract.activate();
assert(intContract.status === CONTRACT_STATUS.ACTIVE, 'Integration contract active');

// 2. Match agents via registry
const intReg = createDefaultRegistry();
const match1 = matchAgent(testSlice.tasks[0], intReg);
assert(match1.agent !== null, 'Agent matched for INT-01');
assert(match1.explicit === true, 'INT-01 has explicit assignee');

const match2 = matchAgent(testSlice.tasks[1], intReg);
assert(match2.agent !== null, 'Agent matched for INT-02');

// 3. Track costs
const intTracker = new CostTracker();
intTracker.record({
  taskId: 'INT-01',
  agentId: match1.agent.id,
  model: 'gpt-5.4',
  inputTokens: 8000,
  outputTokens: 3000,
  sliceId: 'S-INT',
  milestoneId: 'M001',
});
intTracker.record({
  taskId: 'INT-02',
  agentId: match2.agent.id,
  model: 'claude-sonnet-4-6',
  inputTokens: 5000,
  outputTokens: 2000,
  sliceId: 'S-INT',
  milestoneId: 'M001',
});

const intTotals = intTracker.aggregate();
assert(intTotals.count === 2, 'Integration: 2 cost entries');
assert(intTotals.costUsd > 0, 'Integration: cost calculated');

// 4. Check budget
const intBudget = new Budget({ maxUsd: 10.00 });
const intBudgetCheck = intBudget.check(intTracker);
assert(intBudgetCheck.ok, 'Integration: within budget');

// 5. Fulfill contract
intContract.getCriterion('SC-INT-01').meet('API responds 200');
intContract.getCriterion('SC-INT-02').meet('Report at /research/case-law.md');
intContract.getGate(`VG-S-INT-final`).pass('All verified');
assert(intContract.tryFulfill(), 'Integration: contract fulfilled');

// ===========================================================================
// Results
// ===========================================================================

console.log(`\n${'='.repeat(50)}`);
console.log(`Results: ${passed} passed, ${failed} failed`);
if (failed === 0) {
  console.log('ALL TESTS PASSED ✓');
} else {
  console.log('SOME TESTS FAILED ✗');
  process.exit(1);
}
"}

